```python
def is_palindrome(n):
    return str(n) == str(n)[::-1]

def reverse_number(n):
    return int(str(n)[::-1])

def steps_to_palindrome(n):
    count = 0
    while count < 6 and not is_palindrome(n):
        n = n + reverse_number(n)
        count += 1
    if count == 5:
        return n, 5
    else:
        return n - reverse_number(n), count

non_palindrome_sums = 0
for num in range(10, 100):
    if not is_palindrome(num):
        _, steps = steps_to_palindrome(num)
        if steps == 6:
            non_palindrome_sums += num

print(non_palindrome_sums)
```
```output
4528
```
The sum of the non-palindrome integers between 10 and 100 that take exactly six steps to become palindromes is \(\boxed{4528}\).

